proof fn phi_1_temp_pred_equality_intensional_bridge(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
    ensures
        p == q,
{
    temp_pred_equality::<int>(p, q);
}

proof fn phi_2_leads_to_trans_intensional_bridge(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        spec.entails(p.leads_to(q)),
        spec.entails(q.leads_to(r)),
    ensures
        spec.entails(p.leads_to(r)),
{
    leads_to_trans::<int>(spec, p, q, r);
}

proof fn phi_3_leads_to_framed_by_or_intensional_bridge(spec: TempPred<int>, p: TempPred<int>, q: TempPred<int>, r: TempPred<int>)
    requires
        spec.entails(p.leads_to(q)),
    ensures
        spec.entails(p.or(r).leads_to(q.or(r))),
{
    leads_to_framed_by_or::<int>(spec, p, q, r);
}

proof fn phi_4_or_idempotent_equality(p: TempPred<int>, q: TempPred<int>)
    ensures
        p.or(q).or(q) == p.or(q),
{
    temp_pred_equality::<int>(p.or(q).or(q), p.or(q));
}

proof fn phi_5_mutual_entailment_derives_false_if_distinct(p: TempPred<int>, q: TempPred<int>)
    requires
        p.entails(q),
        q.entails(p),
        p !== q,
    ensures
        false,
{
    temp_pred_equality::<int>(p, q);
}
